// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	//STRY0033443 Update Notification - Task Awaiting Assignment (N-14)
	var recipients='';
	var assigned_to = current.assigned_to;
	var primary_assignee = current.primary_assignee;
	var task_owner = current.u_task_requester;
	var reviewer = current.u_reviewer;
	var OUTaskingAuthorities = current.primary_assignee.tasking_authorities;
	var GlobalTaskingAuthorities = current.primary_office.u_global_authorities;
	var currentUser  = gs.getUserID();
	recipients += task_owner + ',';


	if(task_owner != reviewer){
		recipients += reviewer + ',';
	}
	if(assigned_to  != undefined && assigned_to  != ''){
		recipients += assigned_to + ',';
	}

	if((primary_assignee != undefined && primary_assignee != '') && (OUTaskingAuthorities != undefined && OUTaskingAuthorities != '')){
		recipients += OUTaskingAuthorities;
	}else{
		recipients += GlobalTaskingAuthorities;
	}

	gs.eventQueue("x_153465_discovert.NotificationWarningSt",current,recipients,'');

})(current, previous);
